// --- Theme (matches voluntary_prepay_dashboard.jsx) ---
const T = {
  bg: '#0F172A', panel: '#1E293B', panelLight: '#334155',
  text: '#F1F5F9', textDim: '#94A3B8', accent: '#22D3EE',
  blue: '#60A5FA', green: '#34D399', red: '#F87171',
  yellow: '#FBBF24', purple: '#A78BFA',
  border: '#334155', grid: '#475569',
};
const FONT_MONO = 'Consolas, "SF Mono", Menlo, monospace';
const FONT_SANS = 'Inter, "Segoe UI", system-ui, sans-serif';

// --- Reusable wrappers ---
const Panel = ({ title, subtitle, children, style }) => (
  <div style={{
    background: T.panel, border: `1px solid ${T.border}`, borderRadius: 8,
    padding: 16, marginBottom: 16, ...style,
  }}>
    {title && <div style={{ color: T.text, fontSize: 14, fontWeight: 600, marginBottom: 4 }}>{title}</div>}
    {subtitle && <div style={{ color: T.textDim, fontSize: 11, marginBottom: 12, fontFamily: FONT_MONO }}>{subtitle}</div>}
    {children}
  </div>
);

const Stat = ({ label, value, hint, color }) => (
  <div style={{ flex: 1, padding: '12px 14px', background: T.panelLight, borderRadius: 6 }}>
    <div style={{ color: T.textDim, fontSize: 11, fontFamily: FONT_MONO, textTransform: 'uppercase' }}>{label}</div>
    <div style={{ color: color || T.text, fontSize: 22, fontWeight: 600, fontFamily: FONT_MONO, marginTop: 2 }}>{value}</div>
    {hint && <div style={{ color: T.textDim, fontSize: 10, marginTop: 2 }}>{hint}</div>}
  </div>
);

const tooltipStyle = {
  contentStyle: {
    background: T.panel, border: `1px solid ${T.border}`, borderRadius: 4,
    fontFamily: FONT_MONO, fontSize: 12,
  },
  itemStyle: { color: T.text },
  labelStyle: { color: T.textDim },
};

// --- Sigmoid + CPR helpers (used by What-if tab) ---
const sigmoid = (x) => 1 / (1 + Math.exp(-x));
const annualizeCpr = (smm) => 1 - Math.pow(1 - smm, 12);

// =============================================================================
// Tab components
// =============================================================================

function TabOverview({ md, mdE }) {
  const m = md.metadata || {};
  const me = (mdE && mdE.metadata) || {};
  const cmp = md.comparison_to_v6e || {};

  const topFeatures = (md.coefficients || [])
    .map(c => ({ ...c, abs_b: Math.abs(c.beta_scaled) }))
    .sort((a, b) => b.abs_b - a.abs_b).slice(0, 12);

  return (
    <div>
      <Panel title="V6F at a glance"
             subtitle={`${m.n_features}-feature logistic regression  •  trained ${(m.period_range || []).join(' → ')}`}>
        <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap' }}>
          <Stat label="Test AUC" value={(m.test_auc || 0).toFixed(4)}
                hint={cmp.available ? `vs V6E ${(me.test_auc || 0).toFixed(4)}  (Δ${(cmp.auc_delta >= 0 ? '+' : '')}${(cmp.auc_delta || 0).toFixed(4)})` : ''}
                color={T.accent} />
          <Stat label="Test log loss" value={(m.test_log_loss || 0).toFixed(5)}
                hint={cmp.available ? `vs V6E ${(me.test_log_loss || 0).toFixed(5)}` : ''} />
          <Stat label="Base CPR" value={(m.base_cpr || 0).toFixed(2) + '%'}
                hint={`base SMM ${(m.base_smm || 0).toFixed(5)}`} />
          <Stat label="Training events" value={(m.training_events || 0).toLocaleString()}
                hint={`${(m.training_pop_n || 0).toLocaleString()} eligible loan-months`} />
          <Stat label="Features"
                value={`${m.n_features} (V6E ${cmp.v6e_n_features || '?'})`}
                hint={(md.accepted_interactions || []).length + ' interactions accepted'} />
        </div>
      </Panel>

      <Panel title="Top features by |β scaled|"
             subtitle="larger |β| means feature drives more of the prediction at training z-scores">
        <ResponsiveContainer width="100%" height={Math.max(280, 32 * topFeatures.length)}>
          <BarChart data={topFeatures} layout="vertical" margin={{ top: 4, right: 16, bottom: 4, left: 180 }}>
            <CartesianGrid stroke={T.grid} strokeDasharray="3 3" />
            <XAxis type="number" stroke={T.textDim} tick={{ fontFamily: FONT_MONO, fontSize: 11 }} />
            <YAxis type="category" dataKey="feature" stroke={T.textDim}
                   tick={{ fontFamily: FONT_MONO, fontSize: 11 }} width={170} />
            <Tooltip {...tooltipStyle} />
            <Bar dataKey="beta_scaled">
              {topFeatures.map((c, i) =>
                <Cell key={i} fill={c.beta_scaled >= 0 ? T.green : T.red} />
              )}
            </Bar>
          </BarChart>
        </ResponsiveContainer>
      </Panel>

      {cmp.available && (
        <Panel title="V6F vs V6E - quick deltas"
               subtitle="positive AUC delta = V6F is more discriminative; negative log_loss delta = better calibration">
          <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap' }}>
            <Stat label="ΔAUC"
                  value={(cmp.auc_delta >= 0 ? '+' : '') + (cmp.auc_delta || 0).toFixed(4)}
                  color={cmp.auc_delta > 0 ? T.green : T.red} />
            <Stat label="ΔLog-loss"
                  value={(cmp.log_loss_delta >= 0 ? '+' : '') + (cmp.log_loss_delta || 0).toFixed(5)}
                  color={cmp.log_loss_delta < 0 ? T.green : T.red} />
            <Stat label="V6E features dropped" value="7"
                  hint="refi_incentive, in_pen, cum_itm, age (linear), walker_dunlop, berkadia, merchants" />
            <Stat label="V6F features added" value="13"
                  hint="gross_refi, ppp, age x3, mtm x2, post_lockout, size x2, greystone, lument + interactions" />
          </div>
        </Panel>
      )}
    </div>
  );
}

function TabHistoricalFits({ md, mdE }) {
  const yearly = md.yearly || [];
  const monthly = md.monthly || [];
  const yearlyE = (mdE && mdE.yearly) || [];

  const yearlyMerged = yearly.map(y => {
    const e = yearlyE.find(x => x.year === y.year) || {};
    return {
      year: String(y.year), n: y.n,
      actual: y.actual_cpr, v6f_pred: y.pred_cpr, v6e_pred: e.pred_cpr,
    };
  });

  return (
    <div>
      <Panel title="Yearly fit: actual vs predicted CPR"
             subtitle="V6F is the focus; V6E shown as comparison if available">
        <ResponsiveContainer width="100%" height={340}>
          <ComposedChart data={yearlyMerged} margin={{ top: 12, right: 12, bottom: 4, left: 0 }}>
            <CartesianGrid stroke={T.grid} strokeDasharray="3 3" />
            <XAxis dataKey="year" stroke={T.textDim} tick={{ fontFamily: FONT_MONO, fontSize: 11 }} />
            <YAxis stroke={T.textDim} tick={{ fontFamily: FONT_MONO, fontSize: 11 }}
                   label={{ value: 'CPR %', angle: -90, position: 'insideLeft', fill: T.textDim, fontSize: 11 }} />
            <Tooltip {...tooltipStyle} />
            <Legend wrapperStyle={{ color: T.text, fontSize: 12 }} />
            <Bar dataKey="actual" fill={T.accent} name="Actual" />
            <Line type="monotone" dataKey="v6f_pred" stroke={T.green} strokeWidth={2} dot={{ r: 4 }} name="V6F predicted" />
            <Line type="monotone" dataKey="v6e_pred" stroke={T.yellow} strokeWidth={2} strokeDasharray="4 4" dot={{ r: 3 }} name="V6E predicted" />
          </ComposedChart>
        </ResponsiveContainer>
      </Panel>

      <Panel title="Monthly fit (test set only)"
             subtitle={`${monthly.length} months`}>
        <ResponsiveContainer width="100%" height={300}>
          <LineChart data={monthly.map(m => ({
            ...m, period_label: m.period.slice(0, 4) + '-' + m.period.slice(4)
          }))} margin={{ top: 12, right: 16, bottom: 4, left: 0 }}>
            <CartesianGrid stroke={T.grid} strokeDasharray="3 3" />
            <XAxis dataKey="period_label" stroke={T.textDim}
                   tick={{ fontFamily: FONT_MONO, fontSize: 10 }} interval="preserveStartEnd" />
            <YAxis stroke={T.textDim} tick={{ fontFamily: FONT_MONO, fontSize: 11 }}
                   label={{ value: 'CPR %', angle: -90, position: 'insideLeft', fill: T.textDim, fontSize: 11 }} />
            <Tooltip {...tooltipStyle} />
            <Legend wrapperStyle={{ color: T.text, fontSize: 12 }} />
            <Line type="monotone" dataKey="actual_cpr" stroke={T.accent} strokeWidth={2} dot={false} name="Actual" />
            <Line type="monotone" dataKey="pred_cpr" stroke={T.green} strokeWidth={2} dot={false} name="V6F predicted" />
            <ReferenceArea x1="2020-03" x2="2021-12" fill={T.purple} fillOpacity={0.1}
                           label={{ value: 'COVID era', fill: T.textDim, fontSize: 10 }} />
          </LineChart>
        </ResponsiveContainer>
      </Panel>
    </div>
  );
}

function TabSCurve({ md, mdE }) {
  const scurve = md.scurve || [];
  const scurveE = (mdE && mdE.scurve) || [];
  const merged = scurve.map(s => {
    const e = scurveE.find(x => Math.abs((x.ri_mid || 0) - (s.ri_mid || 0)) < 25) || {};
    return {
      ri_mid: s.ri_mid, n: s.n,
      actual: s.actual_cpr, v6f_pred: s.pred_cpr, v6e_pred: e.pred_cpr,
    };
  });
  const issuerScurves = md.issuer_scurves || {};
  const issuerKeys = Object.keys(issuerScurves);
  const labels = (md.metadata && md.metadata.feature_labels) || {};

  return (
    <div>
      <Panel title="S-curve: CPR vs gross refi incentive (bp)"
             subtitle="V6F decouples the rate channel from prepay penalty; mid-ITM (50-200bp) is where V6E underpredicted">
        <ResponsiveContainer width="100%" height={360}>
          <LineChart data={merged} margin={{ top: 12, right: 16, bottom: 4, left: 0 }}>
            <CartesianGrid stroke={T.grid} strokeDasharray="3 3" />
            <XAxis dataKey="ri_mid" stroke={T.textDim} tick={{ fontFamily: FONT_MONO, fontSize: 11 }}
                   label={{ value: 'gross_refi_incentive_bps', position: 'insideBottom', fill: T.textDim, fontSize: 11, offset: -8 }} />
            <YAxis stroke={T.textDim} tick={{ fontFamily: FONT_MONO, fontSize: 11 }}
                   label={{ value: 'CPR %', angle: -90, position: 'insideLeft', fill: T.textDim, fontSize: 11 }} />
            <Tooltip {...tooltipStyle} />
            <Legend wrapperStyle={{ color: T.text, fontSize: 12 }} />
            <ReferenceLine x={0} stroke={T.textDim} strokeDasharray="2 2" />
            <Line type="monotone" dataKey="actual" stroke={T.accent} strokeWidth={2} name="Actual" />
            <Line type="monotone" dataKey="v6f_pred" stroke={T.green} strokeWidth={2} name="V6F" />
            <Line type="monotone" dataKey="v6e_pred" stroke={T.yellow} strokeWidth={2} strokeDasharray="4 4" name="V6E" />
          </LineChart>
        </ResponsiveContainer>
      </Panel>

      {issuerKeys.length > 0 && (
        <Panel title="Per-issuer S-curves" subtitle="actual CPR by RI bucket; V6F predicted overlay">
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))', gap: 12 }}>
            {issuerKeys.map(k => {
              const data = issuerScurves[k];
              const lbl = k === '_other' ? 'Other issuers' : (labels[k] || k);
              return (
                <div key={k} style={{ background: T.panelLight, padding: 8, borderRadius: 6 }}>
                  <div style={{ color: T.text, fontSize: 12, fontWeight: 600, marginBottom: 4, fontFamily: FONT_MONO }}>{lbl}</div>
                  <ResponsiveContainer width="100%" height={140}>
                    <LineChart data={data} margin={{ top: 4, right: 4, bottom: 4, left: 0 }}>
                      <CartesianGrid stroke={T.grid} strokeDasharray="3 3" />
                      <XAxis dataKey="ri_mid" stroke={T.textDim} tick={{ fontFamily: FONT_MONO, fontSize: 9 }} />
                      <YAxis stroke={T.textDim} tick={{ fontFamily: FONT_MONO, fontSize: 9 }} />
                      <Tooltip {...tooltipStyle} />
                      <Line type="monotone" dataKey="actual_cpr" stroke={T.accent} strokeWidth={1.5} dot={false} />
                      <Line type="monotone" dataKey="pred_cpr" stroke={T.green} strokeWidth={1.5} dot={false} strokeDasharray="3 3" />
                    </LineChart>
                  </ResponsiveContainer>
                </div>
              );
            })}
          </div>
        </Panel>
      )}
    </div>
  );
}

function TabCalibration({ md, mdE }) {
  const cal = md.calibration || [];
  const calE = (mdE && mdE.calibration) || [];

  const merged = cal.map((c, i) => {
    const e = calE[i] || {};
    return {
      decile: c.decile,
      v6f_pred: c.pred_cpr, v6f_actual: c.actual_cpr,
      v6e_pred: e.pred_cpr, v6e_actual: e.actual_cpr,
      v6f_gap: (c.actual_cpr - c.pred_cpr).toFixed(2),
      v6e_gap: e.pred_cpr ? (e.actual_cpr - e.pred_cpr).toFixed(2) : null,
    };
  });

  return (
    <div>
      <Panel title="Decile calibration: predicted vs actual CPR"
             subtitle="diagonal = perfect calibration. Gap below=under-prediction, above=over-prediction">
        <ResponsiveContainer width="100%" height={360}>
          <ScatterChart margin={{ top: 12, right: 16, bottom: 12, left: 12 }}>
            <CartesianGrid stroke={T.grid} strokeDasharray="3 3" />
            <XAxis type="number" dataKey="pred_cpr" name="Predicted CPR %"
                   stroke={T.textDim} tick={{ fontFamily: FONT_MONO, fontSize: 11 }}
                   label={{ value: 'Predicted CPR %', position: 'insideBottom', fill: T.textDim, fontSize: 11, offset: -4 }} />
            <YAxis type="number" dataKey="actual_cpr" name="Actual CPR %"
                   stroke={T.textDim} tick={{ fontFamily: FONT_MONO, fontSize: 11 }}
                   label={{ value: 'Actual CPR %', angle: -90, position: 'insideLeft', fill: T.textDim, fontSize: 11 }} />
            <Tooltip {...tooltipStyle} cursor={{ strokeDasharray: '3 3' }} />
            <Legend wrapperStyle={{ color: T.text, fontSize: 12 }} />
            <Scatter name="V6F" data={cal.map(c => ({ pred_cpr: c.pred_cpr, actual_cpr: c.actual_cpr }))} fill={T.green} />
            {calE.length > 0 && (
              <Scatter name="V6E" data={calE.map(c => ({ pred_cpr: c.pred_cpr, actual_cpr: c.actual_cpr }))} fill={T.yellow} />
            )}
            <ReferenceLine segment={[{ x: 0, y: 0 }, { x: 40, y: 40 }]} stroke={T.textDim} strokeDasharray="4 4" />
          </ScatterChart>
        </ResponsiveContainer>
      </Panel>

      <Panel title="Decile residuals (actual - predicted)" subtitle="closer to 0 = better calibrated. V6F vs V6E side-by-side.">
        <ResponsiveContainer width="100%" height={260}>
          <BarChart data={merged} margin={{ top: 12, right: 12, bottom: 4, left: 0 }}>
            <CartesianGrid stroke={T.grid} strokeDasharray="3 3" />
            <XAxis dataKey="decile" stroke={T.textDim} tick={{ fontFamily: FONT_MONO, fontSize: 11 }} />
            <YAxis stroke={T.textDim} tick={{ fontFamily: FONT_MONO, fontSize: 11 }}
                   label={{ value: 'Residual (CPR %)', angle: -90, position: 'insideLeft', fill: T.textDim, fontSize: 11 }} />
            <Tooltip {...tooltipStyle} />
            <Legend wrapperStyle={{ color: T.text, fontSize: 12 }} />
            <ReferenceLine y={0} stroke={T.textDim} />
            <Bar dataKey="v6f_gap" fill={T.green} name="V6F gap" />
            <Bar dataKey="v6e_gap" fill={T.yellow} name="V6E gap" />
          </BarChart>
        </ResponsiveContainer>
      </Panel>
    </div>
  );
}

