// What-if scenario tool: run the V6F logistic in the browser.
function TabWhatIf({ md }) {
  const features = md.metadata?.feature_list || [];
  const coefs = useMemo(
    () => Object.fromEntries((md.coefficients || []).map(c => [c.feature, c])),
    [md]
  );
  const intercept = md.metadata?.intercept_scaled || 0;
  const labels = md.metadata?.feature_labels || {};

  // User-controlled raw inputs (we derive feature values from these)
  const [loanRate, setLoanRate] = useState(5.0);   // %
  const [plcBps, setPlcBps]     = useState(450);   // bp
  const [ppp, setPpp]           = useState(5.0);   // 0-10
  const [age, setAge]           = useState(60);    // months
  const [mtm, setMtm]           = useState(300);
  const [msle, setMsle]         = useState(12);
  const [upbM, setUpbM]         = useState(15);    // millions
  const [postCovid, setPostCovid] = useState(false);
  const [is223a7, setIs223a7]     = useState(false);
  const [is538, setIs538]         = useState(false);
  const [isHc232, setIsHc232]     = useState(false);
  const [lpNc, setLpNc]           = useState(false);
  const [issuer, setIssuer]       = useState('other');
  const [burnRatio, setBurnRatio] = useState(0.2);

  const upb = upbM * 1_000_000;

  // Derived feature vector
  const featVec = useMemo(() => {
    const grossRefi = loanRate * 100 - plcBps;
    const v = {
      gross_refi_incentive_bps: grossRefi,
      prepay_penalty_points:    ppp,
      age_0_36:                 Math.min(age, 36),
      age_36_120:               Math.min(Math.max(age - 36, 0), 84),
      age_120plus:              Math.max(age - 120, 0),
      months_to_maturity:       mtm,
      pre_maturity_flag:        (mtm > 0 && mtm <= 24) ? 1 : 0,
      months_since_lockout_end: Math.max(0, Math.min(24, msle)),
      log_upb:                  Math.log1p(upb),
      small_loan:               upb < 2_000_000 ? 1 : 0,
      large_loan:               upb > 50_000_000 ? 1 : 0,
      burn_ratio:               burnRatio,
      is_post_covid:            postCovid ? 1 : 0,
      is_223a7:                 is223a7 ? 1 : 0,
      is_538:                   is538 ? 1 : 0,
      is_hc_232:                isHc232 ? 1 : 0,
      lp_NC:                    lpNc ? 1 : 0,
      iss_capital_funding:      issuer === 'capital_funding' ? 1 : 0,
      iss_pnc:                  issuer === 'pnc' ? 1 : 0,
      iss_wells_fargo:          issuer === 'wells_fargo' ? 1 : 0,
      iss_dwight:               issuer === 'dwight' ? 1 : 0,
      iss_greystone:            issuer === 'greystone' ? 1 : 0,
      iss_lument_combined:      issuer === 'lument' ? 1 : 0,
    };
    // Interactions
    v['gross_refi__x__prepay_pen']     = v.gross_refi_incentive_bps * v.prepay_penalty_points;
    v['age_0_36__x__lp_NC']            = v.age_0_36 * v.lp_NC;
    v['age_0_36__x__is_hc_232']        = v.age_0_36 * v.is_hc_232;
    v['iss_lument__x__gross_refi']     = v.iss_lument_combined * v.gross_refi_incentive_bps;
    v['iss_dwight__x__gross_refi']     = v.iss_dwight * v.gross_refi_incentive_bps;
    v['iss_greystone__x__gross_refi']  = v.iss_greystone * v.gross_refi_incentive_bps;
    return v;
  }, [loanRate, plcBps, ppp, age, mtm, msle, upbM, postCovid, is223a7, is538, isHc232, lpNc, issuer, burnRatio]);

  // Score using beta_native * (x - mean)  (centered native form, matches Excel)
  const result = useMemo(() => {
    let logit = intercept;
    const contribs = features.map(f => {
      const c = coefs[f] || { beta_native: 0, mean: 0 };
      const x = featVec[f] ?? 0;
      const ctr = c.beta_native * (x - c.mean);
      logit += ctr;
      return { feature: f, label: labels[f] || f, x_native: x,
               contribution_logit: ctr };
    });
    const smm = sigmoid(logit);
    const cpr = annualizeCpr(smm);
    contribs.sort((a, b) => Math.abs(b.contribution_logit) - Math.abs(a.contribution_logit));
    return { logit, smm, cpr, contribs };
  }, [featVec, features, coefs, intercept, labels]);

  const slider = (label, value, setVal, min, max, step, fmt = v => v) => (
    <div style={{ marginBottom: 10 }}>
      <div style={{ display: 'flex', justifyContent: 'space-between',
                    fontFamily: FONT_MONO, fontSize: 11, color: T.textDim }}>
        <span>{label}</span><span style={{ color: T.text }}>{fmt(value)}</span>
      </div>
      <input type="range" min={min} max={max} step={step} value={value}
             onChange={e => setVal(parseFloat(e.target.value))}
             style={{ width: '100%' }} />
    </div>
  );

  const checkbox = (label, val, setVal) => (
    <label style={{ display: 'flex', alignItems: 'center', gap: 6, fontFamily: FONT_MONO, fontSize: 11, color: T.text, marginBottom: 6 }}>
      <input type="checkbox" checked={val} onChange={e => setVal(e.target.checked)} />
      {label}
    </label>
  );

  const issuerOptions = [
    ['other', 'Other'], ['capital_funding', 'Capital Funding'], ['pnc', 'PNC'],
    ['wells_fargo', 'Wells Fargo'], ['dwight', 'Dwight'],
    ['greystone', 'Greystone'], ['lument', 'Lument (incl Red, Hunt)'],
  ];

  return (
    <div style={{ display: 'grid', gridTemplateColumns: '320px 1fr', gap: 16 }}>
      <div>
        <Panel title="Loan inputs" subtitle="drag sliders → CPR + contributions update live">
          {slider('Loan rate %', loanRate, setLoanRate, 1, 10, 0.05, v => v.toFixed(2))}
          {slider('PLC rate (bp)', plcBps, setPlcBps, 100, 750, 5, v => v.toFixed(0))}
          <div style={{ color: T.textDim, fontSize: 10, fontFamily: FONT_MONO, marginTop: -6, marginBottom: 8 }}>
            → gross_refi_incentive_bps = {(loanRate * 100 - plcBps).toFixed(1)}
          </div>
          {slider('Prepay penalty pts', ppp, setPpp, 0, 10, 0.5, v => v.toFixed(1))}
          {slider('Age (months)', age, setAge, 0, 360, 1, v => v.toFixed(0))}
          {slider('Months to maturity', mtm, setMtm, 0, 480, 1, v => v.toFixed(0))}
          {slider('Months since lockout end', msle, setMsle, 0, 36, 1, v => v.toFixed(0))}
          {slider('UPB ($M)', upbM, setUpbM, 0.5, 100, 0.5, v => '$' + v.toFixed(1) + 'M')}
          {slider('Burn ratio', burnRatio, setBurnRatio, 0, 1, 0.01, v => v.toFixed(2))}
          <div style={{ marginTop: 12 }}>
            {checkbox('Post-COVID vintage', postCovid, setPostCovid)}
            {checkbox('223(a)(7) Streamline', is223a7, setIs223a7)}
            {checkbox('538 USDA', is538, setIs538)}
            {checkbox('232 Healthcare', isHc232, setIsHc232)}
            {checkbox('Loan purpose: NC', lpNc, setLpNc)}
          </div>
          <div style={{ marginTop: 8 }}>
            <div style={{ fontFamily: FONT_MONO, fontSize: 11, color: T.textDim, marginBottom: 4 }}>Issuer</div>
            <select value={issuer} onChange={e => setIssuer(e.target.value)}
                    style={{ width: '100%', background: T.panel, color: T.text, border: `1px solid ${T.border}`,
                             padding: 6, fontFamily: FONT_MONO, fontSize: 11, borderRadius: 4 }}>
              {issuerOptions.map(([v, l]) => <option key={v} value={v}>{l}</option>)}
            </select>
          </div>
        </Panel>
      </div>

      <div>
        <Panel title="Predicted CPR for this loan">
          <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap' }}>
            <Stat label="Pred CPR" value={(result.cpr * 100).toFixed(2) + '%'} color={T.accent}
                  hint={`SMM ${(result.smm * 100).toFixed(4)}%`} />
            <Stat label="Logit z" value={result.logit.toFixed(3)} />
            <Stat label="Δ vs base" value={
              ((result.cpr * 100) - (md.metadata?.base_cpr || 0)).toFixed(2) + ' pp'
            } color={result.cpr * 100 > (md.metadata?.base_cpr || 0) ? T.green : T.red} />
          </div>
        </Panel>

        <Panel title="Per-feature contribution (logit units, sorted by |size|)"
               subtitle="contribution_j = beta_native_j × (x_j − mean_j); they sum to logit_z − intercept">
          <ResponsiveContainer width="100%" height={Math.max(360, 28 * result.contribs.length)}>
            <BarChart data={result.contribs} layout="vertical" margin={{ top: 4, right: 12, bottom: 4, left: 200 }}>
              <CartesianGrid stroke={T.grid} strokeDasharray="3 3" />
              <XAxis type="number" stroke={T.textDim} tick={{ fontFamily: FONT_MONO, fontSize: 10 }} />
              <YAxis type="category" dataKey="label" stroke={T.textDim}
                     tick={{ fontFamily: FONT_MONO, fontSize: 10 }} width={190} />
              <Tooltip {...tooltipStyle}
                       formatter={(v, n, p) =>
                         [v.toFixed(4), `Δlogit (x=${(p.payload.x_native || 0).toFixed(3)})`]} />
              <ReferenceLine x={0} stroke={T.textDim} />
              <Bar dataKey="contribution_logit">
                {result.contribs.map((c, i) =>
                  <Cell key={i} fill={c.contribution_logit >= 0 ? T.green : T.red} />)}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </Panel>
      </div>
    </div>
  );
}

function TabAttribution({ md, mdE }) {
  const loans = md.attribution_loans || [];
  const [pickIdx, setPickIdx] = useState(0);
  if (!loans.length) return <Panel title="Attribution loans"><div style={{color: T.textDim}}>No attribution_loans in artifact.</div></Panel>;
  const loan = loans[pickIdx];
  const labels = md.metadata?.feature_labels || {};

  const sorted = [...(loan.contributions || [])]
    .sort((a, b) => Math.abs(b.contribution_logit) - Math.abs(a.contribution_logit))
    .map(c => ({ ...c, label: labels[c.feature] || c.feature }));

  return (
    <div>
      <Panel title="Attribution explorer" subtitle="pick a representative loan; see how each feature contributes to its CPR prediction">
        <div style={{ marginBottom: 12 }}>
          <select value={pickIdx} onChange={e => setPickIdx(parseInt(e.target.value))}
                  style={{ background: T.panel, color: T.text, border: `1px solid ${T.border}`,
                           padding: 6, fontFamily: FONT_MONO, fontSize: 11, borderRadius: 4, width: '100%' }}>
            {loans.map((l, i) => (
              <option key={i} value={i}>
                {l.label} | issuer={l.issuer_key} | period={l.period} | actual_prepay={l.actual_prepay}
              </option>
            ))}
          </select>
        </div>

        <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap', marginBottom: 12 }}>
          <Stat label="Pred CPR" value={(loan.pred_cpr).toFixed(2) + '%'} color={T.accent} />
          <Stat label="Logit z" value={loan.logit_z.toFixed(3)} />
          <Stat label="Pred SMM" value={loan.pred_smm.toFixed(5)} />
          <Stat label="FHA / Purpose" value={`${loan.fha_category} / ${loan.loan_purpose}`} />
          <Stat label="Actual prepay" value={String(loan.actual_prepay)}
                color={loan.actual_prepay ? T.green : T.textDim} />
        </div>

        <ResponsiveContainer width="100%" height={Math.max(420, 26 * sorted.length)}>
          <BarChart data={sorted} layout="vertical" margin={{ top: 4, right: 16, bottom: 4, left: 220 }}>
            <CartesianGrid stroke={T.grid} strokeDasharray="3 3" />
            <XAxis type="number" stroke={T.textDim} tick={{ fontFamily: FONT_MONO, fontSize: 10 }} />
            <YAxis type="category" dataKey="label" stroke={T.textDim}
                   tick={{ fontFamily: FONT_MONO, fontSize: 10 }} width={210} />
            <Tooltip {...tooltipStyle}
                     formatter={(v, n, p) =>
                       [v.toFixed(4), `Δlogit (x=${(p.payload.x_native || 0).toFixed(3)})`]} />
            <ReferenceLine x={0} stroke={T.textDim} />
            <Bar dataKey="contribution_logit">
              {sorted.map((c, i) =>
                <Cell key={i} fill={c.contribution_logit >= 0 ? T.green : T.red} />)}
            </Bar>
          </BarChart>
        </ResponsiveContainer>
      </Panel>
    </div>
  );
}

function TabCoefficients({ md, mdE }) {
  const coefs = md.coefficients || [];
  const v6eCoefs = (mdE && mdE.coefficients) || [];
  const v6eMap = Object.fromEntries(v6eCoefs.map(c => [c.feature, c]));
  const groups = md.metadata?.feature_groups || {};

  return (
    <Panel title="Coefficient table" subtitle={`${coefs.length} V6F features. β_scaled is the standardized coefficient (interpret as Δlogit per 1σ).`}>
      <table style={{ width: '100%', borderCollapse: 'collapse', fontFamily: FONT_MONO, fontSize: 11 }}>
        <thead>
          <tr style={{ background: T.panelLight, color: T.text }}>
            {['#', 'feature', 'group', 'β_scaled', 'β_native', 'mean', 'std', 'V6E β_scaled'].map(h =>
              <th key={h} style={{ padding: 6, textAlign: 'left', borderBottom: `1px solid ${T.border}` }}>{h}</th>
            )}
          </tr>
        </thead>
        <tbody>
          {coefs.map((c, i) => {
            const group = Object.entries(groups).find(([g, items]) => items.includes(c.feature))?.[0] || c.group || '';
            const v6eB = v6eMap[c.feature]?.beta_scaled;
            return (
              <tr key={c.feature} style={{ color: T.textDim, borderBottom: `1px solid ${T.border}` }}>
                <td style={{ padding: 6 }}>{i + 1}</td>
                <td style={{ padding: 6, color: T.text }}>{c.feature}</td>
                <td style={{ padding: 6 }}>{group}</td>
                <td style={{ padding: 6, color: c.beta_scaled >= 0 ? T.green : T.red }}>{c.beta_scaled.toFixed(4)}</td>
                <td style={{ padding: 6 }}>{c.beta_native.toExponential(3)}</td>
                <td style={{ padding: 6 }}>{c.mean.toFixed(4)}</td>
                <td style={{ padding: 6 }}>{c.std.toFixed(4)}</td>
                <td style={{ padding: 6, color: v6eB == null ? T.textDim : (v6eB >= 0 ? T.green : T.red) }}>
                  {v6eB == null ? '(new)' : v6eB.toFixed(4)}
                </td>
              </tr>
            );
          })}
        </tbody>
      </table>
    </Panel>
  );
}

function TabHeadToHead({ md, mdE }) {
  const cmp = md.comparison_to_v6e || {};
  if (!cmp.available) {
    return <Panel title="V6E vs V6F head-to-head"><div style={{color: T.textDim}}>V6E artifact not loaded; comparison unavailable.</div></Panel>;
  }
  const yc = cmp.yearly_compare || [];
  const cc = cmp.calibration_compare || [];

  const yearlyData = yc.map(y => ({
    year: String(y.year),
    actual: y.actual_cpr,
    v6e_pred: y.v6e_pred_cpr,
    v6f_pred: y.v6f_pred_cpr,
    v6e_gap: y.v6e_pred_cpr ? Math.abs(y.actual_cpr - y.v6e_pred_cpr) : null,
    v6f_gap: Math.abs(y.actual_cpr - y.v6f_pred_cpr),
  }));

  return (
    <div>
      <Panel title="V6E vs V6F: did the retrain actually help?">
        <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap' }}>
          <Stat label="V6E test AUC" value={cmp.v6e_test_auc.toFixed(4)} />
          <Stat label="V6F test AUC" value={cmp.v6f_test_auc.toFixed(4)} color={T.accent} />
          <Stat label="ΔAUC" value={(cmp.auc_delta >= 0 ? '+' : '') + cmp.auc_delta.toFixed(4)}
                color={cmp.auc_delta >= 0 ? T.green : T.red} />
          <Stat label="ΔLog-loss" value={(cmp.log_loss_delta >= 0 ? '+' : '') + cmp.log_loss_delta.toFixed(5)}
                color={cmp.log_loss_delta < 0 ? T.green : T.red} />
        </div>
      </Panel>

      <Panel title="Per-year |actual − pred| gap" subtitle="lower is better. V6F should narrow the gap on most years (esp. 2020-21 COVID).">
        <ResponsiveContainer width="100%" height={300}>
          <BarChart data={yearlyData} margin={{ top: 12, right: 16, bottom: 4, left: 0 }}>
            <CartesianGrid stroke={T.grid} strokeDasharray="3 3" />
            <XAxis dataKey="year" stroke={T.textDim} tick={{ fontFamily: FONT_MONO, fontSize: 11 }} />
            <YAxis stroke={T.textDim} tick={{ fontFamily: FONT_MONO, fontSize: 11 }}
                   label={{ value: 'CPR pp', angle: -90, position: 'insideLeft', fill: T.textDim, fontSize: 11 }} />
            <Tooltip {...tooltipStyle} />
            <Legend wrapperStyle={{ color: T.text, fontSize: 12 }} />
            <Bar dataKey="v6e_gap" fill={T.yellow} name="V6E |gap|" />
            <Bar dataKey="v6f_gap" fill={T.green} name="V6F |gap|" />
          </BarChart>
        </ResponsiveContainer>
      </Panel>

      <Panel title="Decile calibration: V6F vs V6E" subtitle="actual − pred residual by decile, both models.">
        <ResponsiveContainer width="100%" height={280}>
          <BarChart data={cc.map(c => ({
            decile: c.decile,
            v6e_resid: c.v6e_pred_cpr ? (c.v6e_actual_cpr - c.v6e_pred_cpr) : null,
            v6f_resid: c.v6f_actual_cpr - c.v6f_pred_cpr,
          }))} margin={{ top: 12, right: 16, bottom: 4, left: 0 }}>
            <CartesianGrid stroke={T.grid} strokeDasharray="3 3" />
            <XAxis dataKey="decile" stroke={T.textDim} tick={{ fontFamily: FONT_MONO, fontSize: 11 }} />
            <YAxis stroke={T.textDim} tick={{ fontFamily: FONT_MONO, fontSize: 11 }}
                   label={{ value: 'Residual (pp)', angle: -90, position: 'insideLeft', fill: T.textDim, fontSize: 11 }} />
            <Tooltip {...tooltipStyle} />
            <Legend wrapperStyle={{ color: T.text, fontSize: 12 }} />
            <ReferenceLine y={0} stroke={T.textDim} />
            <Bar dataKey="v6e_resid" fill={T.yellow} name="V6E residual" />
            <Bar dataKey="v6f_resid" fill={T.green} name="V6F residual" />
          </BarChart>
        </ResponsiveContainer>
      </Panel>
    </div>
  );
}

function TabInteractions({ md }) {
  const accepted = md.accepted_interactions || [];
  const coefs = Object.fromEntries((md.coefficients || []).map(c => [c.feature, c]));

  if (!accepted.length) {
    return <Panel title="Interactions"
                  subtitle="No interactions passed the AUC-lift > 0.005 gate in this fit. Pure additive logit.">
      <div style={{ color: T.textDim, fontSize: 12 }}>
        Candidates considered (BAM-motivated):
        <ul style={{ marginTop: 8 }}>
          <li>age_0_36 × lp_NC — pent-up post-conversion refi (BAM p9)</li>
          <li>age_0_36 × is_hc_232 — HC age-conditional multiplier (BAM p10)</li>
          <li>gross_refi × prepay_pen — penalty diminishes with high incentive (BAM p26/p33)</li>
          <li>iss_lument / iss_dwight / iss_greystone × gross_refi — issuer-specific deep-ITM aggressiveness</li>
        </ul>
      </div>
    </Panel>;
  }

  return (
    <div>
      <Panel title="Accepted interactions"
             subtitle={`${accepted.length} interaction${accepted.length > 1 ? 's' : ''} passed the AUC-lift > 0.005 gate`}>
        <table style={{ width: '100%', borderCollapse: 'collapse', fontFamily: FONT_MONO, fontSize: 11, color: T.text }}>
          <thead>
            <tr style={{ background: T.panelLight }}>
              {['name', 'left', 'right', 'β_scaled', 'sign', 'reading'].map(h =>
                <th key={h} style={{ padding: 6, textAlign: 'left', borderBottom: `1px solid ${T.border}` }}>{h}</th>
              )}
            </tr>
          </thead>
          <tbody>
            {accepted.map(({ name, left, right }) => {
              const c = coefs[name];
              const beta = c ? c.beta_scaled : 0;
              const sign = beta > 0 ? 'reinforce' : 'attenuate';
              const reading = beta > 0
                ? `When ${left} is high, the effect of ${right} is amplified.`
                : `When ${left} is high, the effect of ${right} is dampened (BAM-style multiplier-down).`;
              return (
                <tr key={name} style={{ borderBottom: `1px solid ${T.border}` }}>
                  <td style={{ padding: 6 }}>{name}</td>
                  <td style={{ padding: 6, color: T.textDim }}>{left}</td>
                  <td style={{ padding: 6, color: T.textDim }}>{right}</td>
                  <td style={{ padding: 6, color: beta >= 0 ? T.green : T.red }}>{beta.toFixed(4)}</td>
                  <td style={{ padding: 6 }}>{sign}</td>
                  <td style={{ padding: 6, color: T.textDim }}>{reading}</td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </Panel>
    </div>
  );
}

// =============================================================================
// Top-level shell
// =============================================================================

const TABS = [
  { key: 'overview',     label: 'Overview',         render: TabOverview },
  { key: 'historical',   label: 'Historical fits',  render: TabHistoricalFits },
  { key: 'scurve',       label: 'S-curve',          render: TabSCurve },
  { key: 'calibration',  label: 'Calibration',      render: TabCalibration },
  { key: 'cohorts',      label: 'Cohort cuts',      render: TabCohorts },
  { key: 'whatif',       label: 'What-if',          render: TabWhatIf },
  { key: 'attribution',  label: 'Attribution',      render: TabAttribution },
  { key: 'coeffs',       label: 'Coefficients',     render: TabCoefficients },
  { key: 'h2h',          label: 'V6E vs V6F',       render: TabHeadToHead },
  { key: 'interactions', label: 'Interactions',     render: TabInteractions },
];

export default function V6FDashboard() {
  const [tab, setTab] = useState('overview');
  const md = MODEL_DATA_V6F;
  const mdE = MODEL_DATA_V6E;
  const Tab = TABS.find(t => t.key === tab)?.render || TabOverview;

  if (md._placeholder) {
    return (
      <div style={{ background: T.bg, color: T.text, padding: 24, fontFamily: FONT_SANS, minHeight: '100vh' }}>
        <h1>V6F dashboard - data not yet emitted</h1>
        <pre style={{ background: T.panel, padding: 12, borderRadius: 6, fontFamily: FONT_MONO, fontSize: 12 }}>
{`Run: GNMA_PANEL_PARQUET=working/gnma_mf_panel.parquet python3 train_v6f.py --emit-dashboard
That script string-replaces the MODEL_DATA_V6F / MODEL_DATA_V6E lines at the top of v6f_dashboard.jsx.`}
        </pre>
      </div>
    );
  }

  return (
    <div style={{ background: T.bg, color: T.text, fontFamily: FONT_SANS,
                  minHeight: '100vh', padding: 16 }}>
      <header style={{ marginBottom: 16 }}>
        <div style={{ display: 'flex', alignItems: 'baseline', gap: 12 }}>
          <h1 style={{ margin: 0, fontSize: 22, fontWeight: 600 }}>
            V6F Voluntary Prepayment Model
          </h1>
          <span style={{ color: T.textDim, fontFamily: FONT_MONO, fontSize: 11 }}>
            {md.metadata?.n_features} features  •  test AUC {md.metadata?.test_auc?.toFixed(4)}
            {(md.comparison_to_v6e?.auc_delta != null) && (
              <span style={{ color: md.comparison_to_v6e.auc_delta > 0 ? T.green : T.red, marginLeft: 8 }}>
                (Δ{md.comparison_to_v6e.auc_delta >= 0 ? '+' : ''}{md.comparison_to_v6e.auc_delta.toFixed(4)} vs V6E)
              </span>
            )}
          </span>
        </div>
        <div style={{ color: T.textDim, fontFamily: FONT_MONO, fontSize: 11, marginTop: 4 }}>
          {md.metadata?.description}
        </div>
      </header>

      <nav style={{ display: 'flex', flexWrap: 'wrap', gap: 4, marginBottom: 16 }}>
        {TABS.map(t => (
          <button key={t.key} onClick={() => setTab(t.key)}
                  style={{
                    background: tab === t.key ? T.accent : T.panel,
                    color: tab === t.key ? T.bg : T.text,
                    border: `1px solid ${T.border}`,
                    borderRadius: 4, padding: '6px 12px',
                    fontFamily: FONT_MONO, fontSize: 11, cursor: 'pointer',
                    fontWeight: tab === t.key ? 600 : 400,
                  }}>{t.label}</button>
        ))}
      </nav>

      <main>
        <Tab md={md} mdE={mdE} />
      </main>

      <footer style={{ marginTop: 24, color: T.textDim, fontFamily: FONT_MONO, fontSize: 10 }}>
        Built from model_data_v6f.json &amp; model_data_v6e.json. Refresh: python3 train_v6f.py --emit-dashboard
      </footer>
    </div>
  );
}
